<template>
  <div>
    <v-toolbar flat color="white">
      <v-toolbar-title>My Listings</v-toolbar-title>
      <v-divider
        class="mx-2"
        inset
        vertical
      ></v-divider>
      <v-spacer></v-spacer>
      <v-dialog v-model="dialog" max-width="800px">
        <v-btn slot="activator" color="primary" dark class="mb-2">New Listing</v-btn>
        <v-card>
          <v-card-title>
            <span class="headline">{{ formTitle }}</span>
            <span class="editedItem">{{ editedItem.hostId }}</span>
          </v-card-title>

          <v-card-text>
            <v-container grid-list-md>
              <v-layout wrap>
                <v-flex xs12 sm6 md6 lg6>
                  <v-text-field v-model="editedItem.listingName" label="Listing Name"></v-text-field>
                </v-flex>
<!--                 <v-flex xs12 sm6 md6 lg6>
                  <v-text-field v-model="editedItem.listingId" :disabled="disabled" label="Listing ID"></v-text-field>
                </v-flex> -->
                <v-flex xs12 sm6 md6 lg6>
                  <v-text-field v-model="editedItem.listingUrl" label="Listing URL"></v-text-field>
                </v-flex>
<!--                 <v-flex xs12 sm6 md6 lg6>
                  <v-text-field v-model="editedItem.paymentStatus" :disabled="disabled"  label="Payment Status"></v-text-field>
                </v-flex>
                <v-flex xs12 sm6 md6 lg6>
                  <v-text-field v-model="editedItem.registeredOn" :disabled="disabled" label="Registered On"></v-text-field>
                </v-flex>
 -->              </v-layout>
            </v-container>
          </v-card-text>

          <v-card-actions>
            <v-spacer></v-spacer>
            <v-btn color="blue darken-1" flat @click="close">Cancel</v-btn>
            <v-btn color="blue darken-1" flat @click="save">Save</v-btn>
<form action="https://www.sandbox.paypal.com/cgi-bin/webscr" method="post" target="_top">
<input type="hidden" name="cmd" value="_s-xclick">
<input type="hidden" name="hosted_button_id" value="LTMRTKXUHY3D2">
<input type="image" src="https://www.sandbox.paypal.com/en_US/i/btn/btn_subscribe_SM.gif" border="0" name="submit" alt="PayPal - The safer, easier way to pay online!">
<img alt="" border="0" src="https://www.sandbox.paypal.com/en_US/i/scr/pixel.gif" width="1" height="1">
</form>
          </v-card-actions>
        </v-card>
      </v-dialog>
    </v-toolbar>
    <v-data-table
      :headers="headers"
      :items="listings"
      :pagination.sync="pagination"
      class="elevation-1"
    >
      <template slot="items" slot-scope="props">
        <!-- <td class="text-xs-left">{{ props.item.hostId }}</td> -->
        <!-- <td class="text-xs-left">{{ props.item.listingId }}</td> -->
        <td class="text-xs-left">
          <v-icon
            medium
            class="mr-2"
            color="primary"
            @click="editItem(props.item)"
          >
            edit
          </v-icon>
        </td>
        <td class="text-xs-left">{{ props.item.listingName }}</td>
        <td class="text-xs-left">{{ props.item.listingUrl }}</td>
        <td class="text-xs-left">{{ props.item.paymentStatus }}</td>
        <td class="text-xs-left">{{ props.item.registeredOn }}</td>
        <td class="text-xs-right">
        <!-- <td class="justify-center layout px-0"> -->
          <v-icon
            medium
            class="mr-2"
            color="primary"
            @click="pickListing({ listingId: props.item.listingId, listingName: props.item.listingName })"
          >
            dehaze
          </v-icon>
        </td>
      </template>
    </v-data-table>
  </div>
</template>

<style scoped>
  table.v-table thead tr th {
    font-size: 28px;
  }
  table.v-table tbody tr td {
    font-size: 20px;
  }
</style>

<script>
import { mapState, mapGetters, mapActions } from 'vuex'  
import { CallDialog } from '@/utils'
import store from '@/store'

export default {
  data: () => ({
    dialog: false,
    headers: [
      // {
      //   text: 'Host ID',
      //   align: 'left',
      //   sortable: false,
      //   value: 'hostId'
      // },
      // { text: 'Listing ID', value: 'listingId', align: 'left', sortable: true},
      { text: 'Edit', value: 'hostId', align: 'left', sortable: false },
      { text: 'Listing Name', value: 'listingName', align: 'left', sortable: false},
      { text: 'URL', value: 'listingUrl', align: 'left', sortable: false},
      { text: 'Payment Status', value: 'paymentStatus', align: 'left', sortable: true},
      { text: 'Registered On', value: 'registeredOn', align: 'left', sortable: true},
      { text: 'Resevations', value: 'hostId', align: 'right', sortable: false }
    ],
    editedIndex: -1,
    editedItem: {
      hostId: '',
      listingId: '',
      listingName: '',
      listingUrl: '',
      paymentStatus: '',
      registeredOn: ''
    },
    defaultItem: {
      hostId: '',
      listingId: '',
      listingName: '',
      listingUrl: '',
      paymentStatus: '',
      registeredOn: ''
    },
    pagination: {
      descending: true,
      page: 1,
      rowsPerPage: 25,
      sortBy: 'registeredOn',
      totalItems: 0,
      rowsPerPageItems: [10,25,{"text":"$vuetify.dataIterator.rowsPerPageAll","value":-1}]
    },
  }),

  computed: {
    formTitle () {
      return this.editedIndex === -1 ? 'New Listing' : 'Edit Listing'
    },
    disabled () {
      return this.editedIndex === -1 ? false : true
    },
    ...mapState({
      listings: state => state.host.listings,
    }),
  },

  watch: {
    dialog (val) {
      val || this.close()
    }
  },
/*
  created () {
    this.loadListings().catch(error => {
      CallDialog(error)
    })
  },
*/
  async beforeRouteEnter (to, from, next) {
    const error = await store.dispatch('host/loadListings').catch(error => {
      return error
    })

    if (error) {
      CallDialog(error)
    } else {
      next()
    }
  },
  async beforeRouteUpdate (to, from, next) {
    const error = await store.dispatch('host/loadListings').catch(error => {      
      return error
    })

    if (error) {
      CallDialog(error)
    } else {
      next()
    }
  },
  methods: {

    editItem (item) {
      this.editedIndex = this.listings.indexOf(item)
      this.editedItem = Object.assign({}, item)
      this.dialog = true
    },

    // deleteItem (item) {
    //   const index = this.desserts.indexOf(item)
    //   confirm('Are you sure you want to delete this item?') && this.desserts.splice(index, 1)
    // },

    close () {
      this.dialog = false
      setTimeout(() => {
        this.editedItem = Object.assign({}, this.defaultItem)
        this.editedIndex = -1
      }, 10)
    },

    async save () {
      if (this.editedIndex > -1) {
        const error = await this.updateListing({
          params: this.editedItem,
          index: this.editedIndex
        }).catch(e => {
          console.error('updateListing', e)
          return e
        })

        if (error) {
          CallDialog(error)  
        } else {
          this.close()
        }
      } else {
        console.log('this.editedItem', this.editedItem)
        this.editedItem.registeredOn = ((new Date).toISOString()).substring(0,10)
        this.editedItem.paymentStatus = ' '
        const error = await this.createListing(this.editedItem).catch(e => {
          console.error('createListing', e)
          return e
        })

        if (error) {
          CallDialog(error)  
        } else {
          this.close()
        }
      }
    },
    ...mapActions({
      loadListings: 'host/loadListings',
      pickListing: 'host/pickListing',
      updateListing: 'host/updateListing',
      createListing: 'host/createListing'
    })
  }
}
</script>